import{_ as e,o as a,c as i,ag as o}from"./chunks/framework.GolXoAlY.js";const u=JSON.parse('{"title":"Agent 操作规范","description":"","frontmatter":{"title":"Agent 操作规范","date":"2026-04-17T00:00:00.000Z","type":"meta","tags":["system","agents"]},"headers":[],"relativePath":"agents.md","filePath":"agents.md","lastUpdated":1776444206000}'),l={name:"agents.md"};function r(d,t,n,s,c,h){return a(),i("div",null,[...t[0]||(t[0]=[o('<h1 id="agent-操作规范" tabindex="-1">Agent 操作规范 <a class="header-anchor" href="#agent-操作规范" aria-label="Permalink to &quot;Agent 操作规范&quot;">​</a></h1><p>本文件定义 AI 助手在操作 Quokka Wiki 时必须遵循的行为准则。</p><hr><h2 id="核心原则" tabindex="-1">核心原则 <a class="header-anchor" href="#核心原则" aria-label="Permalink to &quot;核心原则&quot;">​</a></h2><ol><li><strong>停止重新推导，开始编译</strong> — 每次操作都应让知识库更富</li><li><strong>先更新已有，后创建新页</strong> — 避免孤儿页面</li><li><strong>每次操作必须记录 log</strong> — 时间戳、动作类型、变更摘要</li><li><strong>严格遵守 schema.md 中的目录结构</strong> — 页面按类型存放，角色通过 frontmatter 标签</li></ol><hr><h2 id="标准工作流" tabindex="-1">标准工作流 <a class="header-anchor" href="#标准工作流" aria-label="Permalink to &quot;标准工作流&quot;">​</a></h2><h3 id="_1-ingest-两步式" tabindex="-1">1. Ingest（两步式） <a class="header-anchor" href="#_1-ingest-两步式" aria-label="Permalink to &quot;1. Ingest（两步式）&quot;">​</a></h3><p><strong>第一步（分析）</strong>：LLM 阅读来源 → 结构化分析</p><ul><li>关键实体、概念、论点</li><li>与现有 wiki 内容的关联</li><li>与现有知识的矛盾和张力</li><li>建议的 wiki 结构</li></ul><p><strong>第二步（生成）</strong>：基于分析 → 生成 wiki 文件</p><ol><li>保存原始来源到 <code>raw/sources/</code> （不可变）</li><li>创建 <code>sources/</code> 摘要页（带 frontmatter，type: source）</li><li>创建/更新 <code>entities/</code> 和 <code>concepts/</code> 页面（带交叉引用）</li><li>更新 <code>index.md</code> — 添加新页面到目录</li><li>重生 <code>overview.md</code> — 摘要当前知识库状态</li><li>追加 <code>log.md</code> — 记录本次 ingest 详情</li><li>Git commit + push</li></ol><h3 id="_2-query-回答问题" tabindex="-1">2. Query（回答问题） <a class="header-anchor" href="#_2-query-回答问题" aria-label="Permalink to &quot;2. Query（回答问题）&quot;">​</a></h3><ul><li>先搜索 wiki 页面，再搜索 raw 来源</li><li>结合多个页面信息组织答案</li><li>高质量答案可回收为 <code>queries/</code> 下的新页面</li></ul><h3 id="_3-lint-健康检查" tabindex="-1">3. Lint（健康检查） <a class="header-anchor" href="#_3-lint-健康检查" aria-label="Permalink to &quot;3. Lint（健康检查）&quot;">​</a></h3><ul><li>检查孤儿页面（无入度链接）</li><li>检查断链</li><li>检查过时内容</li><li>检查缺少 frontmatter 的页面</li><li>在 <code>log.md</code> 中记录 lint 结果</li></ul><hr><h2 id="四角色分配指南" tabindex="-1">四角色分配指南 <a class="header-anchor" href="#四角色分配指南" aria-label="Permalink to &quot;四角色分配指南&quot;">​</a></h2><table tabindex="0"><thead><tr><th>来源特征</th><th>分配到</th></tr></thead><tbody><tr><td>包装材料、结构、工艺、趋势、案例</td><td><code>packaging</code> 标签</td></tr><tr><td>品牌视觉、VI、Logo、重塑、趋势</td><td><code>branding</code> 标签</td></tr><tr><td>用户需求、数据分析、策略、项目管理</td><td><code>pm</code> 标签</td></tr><tr><td>习惯、思维、沟通、成长、系统</td><td><code>soft-skills</code> 标签</td></tr></tbody></table><p><strong>跨角色来源</strong>：判断核心论点在哪个角色，主页面放在该角色下，在 frontmatter 中用 <code>role: [packaging, branding]</code> 标注。</p>',20)])])}const m=e(l,[["render",r]]);export{u as __pageData,m as default};
